#!/usr/bin/env python3
from pathlib import Path
import base64
import re
import shutil
import subprocess
import tempfile

MAIN = Path("lib/main.dart")
QUICK = Path("lib/quick_modes.dart")
ADVANCED = Path("lib/advanced_modes.dart")
PUBSPEC = Path("pubspec.yaml")
TARGET = Path("lib/social_features.dart")

SOCIAL_B64 = """"""

def run(command):
    print("$ " + " ".join(command))
    return subprocess.run(command, check=True)

for path in [MAIN, QUICK, ADVANCED, PUBSPEC]:
    if not path.exists():
        raise SystemExit(
            f"Gerekli dosya bulunamadı: {path}\n"
            "Kurulumu BilgiRotasi deposunun ana klasöründe çalıştır."
        )

branch = subprocess.check_output(
    ["git", "branch", "--show-current"],
    text=True,
).strip()

if branch != "main":
    raise SystemExit(
        "Bu geliştirme yalnızca main dalına kurulabilir.\n"
        f"Şu anki dal: {branch or '(belirsiz)'}\n"
        "Önce: git switch main"
    )

main = MAIN.read_text(encoding="utf-8")
quick = QUICK.read_text(encoding="utf-8")
advanced = ADVANCED.read_text(encoding="utf-8")
pubspec = PUBSPEC.read_text(encoding="utf-8")

if "part 'social_features.dart';" in main or TARGET.exists():
    raise SystemExit(
        "Sosyal ve meydan okuma sistemi zaten kurulmuş görünüyor."
    )

required_main = [
    "part 'accessibility_settings.dart';",
    "import 'package:shared_preferences/shared_preferences.dart';",
    "const AccessibilitySettingsButton(),",
    "class _CareerStatsScreenState",
    "class MarathonResultScreen",
    "class _WinnerScreenState",
    "_buildRankingCard(),",
    "Bilgi Rotası • Sürüm 1.27",
]

required_quick = [
    "class QuickModeResultScreen",
    "required this.score",
    "required this.detail",
    "class CategoryDuelGameScreen",
]

required_advanced = [
    "class AdvancedLeaderboardResultScreen",
    "required this.standings",
]

for marker in required_main:
    if marker not in main:
        raise SystemExit(
            f"Beklenen main.dart bölümü bulunamadı: {marker}"
        )

for marker in required_quick:
    if marker not in quick:
        raise SystemExit(
            f"Beklenen quick_modes.dart bölümü bulunamadı: {marker}"
        )

for marker in required_advanced:
    if marker not in advanced:
        raise SystemExit(
            f"Beklenen advanced_modes.dart bölümü bulunamadı: {marker}"
        )

version_match = re.search(
    r"^version:\s*(\d+)\.(\d+)\.(\d+)\+(\d+)\s*$",
    pubspec,
    flags=re.MULTILINE,
)

if version_match is None:
    raise SystemExit("pubspec.yaml sürüm satırı okunamadı.")

major, minor, patch, build = map(
    int,
    version_match.groups(),
)

if (major, minor) != (1, 27):
    raise SystemExit(
        "Bu paket 1.27.x sürümü için hazırlandı.\n"
        f"Depodaki sürüm: {major}.{minor}.{patch}+{build}"
    )

new_version = f"1.28.0+{build + 1}"

backup_dir = Path(tempfile.mkdtemp(
    prefix="bilgi_rotasi_social_"
))
committed = False

try:
    shutil.copy2(MAIN, backup_dir / "main.dart")
    shutil.copy2(QUICK, backup_dir / "quick_modes.dart")
    shutil.copy2(ADVANCED, backup_dir / "advanced_modes.dart")
    shutil.copy2(PUBSPEC, backup_dir / "pubspec.yaml")

    TARGET.write_text(
        base64.b64decode(SOCIAL_B64).decode("utf-8"),
        encoding="utf-8",
    )

    main = main.replace(
        "import 'package:shared_preferences/shared_preferences.dart';",
        "import 'package:shared_preferences/shared_preferences.dart';\n"
        "import 'package:share_plus/share_plus.dart';",
        1,
    )

    main = main.replace(
        "part 'accessibility_settings.dart';",
        "part 'accessibility_settings.dart';\n"
        "part 'social_features.dart';",
        1,
    )

    home_marker = """                const AccessibilitySettingsButton(),
                const SizedBox(height: 16),
                _buildNewGameCard(),"""

    if home_marker not in main:
        raise RuntimeError(
            "Ana ekran sosyal düğme ekleme noktası bulunamadı."
        )

    main = main.replace(
        home_marker,
        """                const AccessibilitySettingsButton(),
                const SizedBox(height: 10),
                SocialHomeButton(
                  questionBank: widget.questionBank,
                ),
                const SizedBox(height: 16),
                _buildNewGameCard(),""",
        1,
    )

    career_start = main.index(
        "class _CareerStatsScreenState"
    )
    career_end = main.index(
        "class HomeScreen",
        career_start,
    )
    career_block = main[career_start:career_end]

    career_marker = """                  _buildHero(stats),
                  const SizedBox(height: 16),
                  const XpCareerCard(),"""

    if career_marker not in career_block:
        raise RuntimeError(
            "Kariyer paylaşım düğmesi ekleme noktası bulunamadı."
        )

    career_block = career_block.replace(
        career_marker,
        """                  _buildHero(stats),
                  const SizedBox(height: 10),
                  FutureBuilder<XpProgress>(
                    future: XpProgressService.load(),
                    builder: (context, xpSnapshot) {
                      final xp = xpSnapshot.data;
                      if (xp == null) {
                        return const SizedBox.shrink();
                      }

                      return SocialShareButton(
                        title: 'Bilgi Rotası Kariyerim',
                        text: SocialShareService.careerText(
                          stats,
                          xp,
                        ),
                      );
                    },
                  ),
                  const SizedBox(height: 16),
                  const XpCareerCard(),""",
        1,
    )

    main = (
        main[:career_start]
        + career_block
        + main[career_end:]
    )

    marathon_start = main.index(
        "class MarathonResultScreen"
    )
    marathon_end = main.index(
        "class PlayerSetupScreen",
        marathon_start,
    )
    marathon_block = main[
        marathon_start:marathon_end
    ]

    marathon_capture_marker = """                const SizedBox(height: 18),
                Container(
                  padding: const EdgeInsets.all(24),"""

    if marathon_capture_marker not in marathon_block:
        raise RuntimeError(
            "Maraton aile rekoru ekleme noktası bulunamadı."
        )

    marathon_block = marathon_block.replace(
        marathon_capture_marker,
        """                FamilyRecordCapture.single(
                  name: AppPreferencesService
                      .current.defaultPlayerName,
                  mode: 'Soru Maratonu',
                  score: correct,
                  total: questionCount,
                  won: correct >= max(1, questionCount ~/ 2),
                ),
                const SizedBox(height: 18),
                Container(
                  padding: const EdgeInsets.all(24),""",
        1,
    )

    marathon_button_marker = """                const SizedBox(height: 18),
                FilledButton.icon(
                  onPressed: () {
                    Navigator.of(context).pushReplacement(
                      MaterialPageRoute(
                        builder: (_) => MarathonSetupScreen("""

    if marathon_button_marker not in marathon_block:
        raise RuntimeError(
            "Maraton paylaşım düğmesi ekleme noktası bulunamadı."
        )

    marathon_block = marathon_block.replace(
        marathon_button_marker,
        """                const SizedBox(height: 15),
                SocialShareButton(
                  dark: true,
                  title: 'Bilgi Rotası Maraton Sonucu',
                  text: SocialShareService.resultText(
                    title: '⚡ Soru Maratonu',
                    score: '$correct / $questionCount',
                    detail: '$modeLabel • Başarı %$percentage • '
                        'En iyi seri $maxStreak',
                  ),
                ),
                const SizedBox(height: 10),
                FilledButton.icon(
                  onPressed: () {
                    Navigator.of(context).pushReplacement(
                      MaterialPageRoute(
                        builder: (_) => MarathonSetupScreen(""",
        1,
    )

    main = (
        main[:marathon_start]
        + marathon_block
        + main[marathon_end:]
    )

    winner_start = main.index(
        "class _WinnerScreenState"
    )
    winner_end = main.index(
        "class WinnerConfettiPainter",
        winner_start,
    )
    winner_block = main[winner_start:winner_end]

    winner_marker = """                    _buildRankingCard(),"""

    if winner_marker not in winner_block:
        raise RuntimeError(
            "Şampiyon paylaşım bölümü bulunamadı."
        )

    winner_block = winner_block.replace(
        winner_marker,
        """                    _buildRankingCard(),
                    FamilyRecordCapture.board(
                      players: widget.players,
                      winner: widget.winner,
                    ),
                    const SizedBox(height: 10),
                    SocialShareButton(
                      dark: true,
                      title: 'Bilgi Rotası Şampiyonu',
                      text: <String>[
                        '🧭 BİLGİ ROTASI',
                        '🏆 ${widget.winner.name} şampiyon!',
                        '${widget.winner.correctAnswers} doğru • '
                            '${widget.winner.badges.length}/6 rozet',
                        '',
                        'Aynı telefonda bilgi düellosu!',
                      ].join('\\n'),
                    ),""",
        1,
    )

    main = (
        main[:winner_start]
        + winner_block
        + main[winner_end:]
    )

    quick_capture_marker = """              children: [
                Text(
                  title,"""

    if quick_capture_marker not in quick:
        raise RuntimeError(
            "Hızlı mod rekor kayıt noktası bulunamadı."
        )

    quick = quick.replace(
        quick_capture_marker,
        """              children: [
                FamilyRecordCapture.single(
                  name: AppPreferencesService
                      .current.defaultPlayerName,
                  mode: title,
                  score:
                      SocialShareService.firstNumber(score),
                  total: max(
                    1,
                    SocialShareService.firstNumber(score),
                  ),
                  won: true,
                ),
                Text(
                  title,""",
        1,
    )

    quick_share_marker = """                const SizedBox(height: 18),
                FilledButton.icon(
                  onPressed: () {
                    Navigator.of(context).pushReplacement(
                      MaterialPageRoute(builder: replayBuilder),"""

    if quick_share_marker not in quick:
        raise RuntimeError(
            "Hızlı mod paylaşım düğmesi ekleme noktası bulunamadı."
        )

    quick = quick.replace(
        quick_share_marker,
        """                const SizedBox(height: 15),
                SocialShareButton(
                  dark: true,
                  title: title,
                  text: SocialShareService.resultText(
                    title: title,
                    score: score,
                    detail: detail,
                    bonusXp: bonusXp,
                  ),
                ),
                const SizedBox(height: 10),
                FilledButton.icon(
                  onPressed: () {
                    Navigator.of(context).pushReplacement(
                      MaterialPageRoute(builder: replayBuilder),""",
        1,
    )

    advanced_capture_marker = """              children: [
                Text(
                  title,"""

    if advanced_capture_marker not in advanced:
        raise RuntimeError(
            "Gelişmiş mod rekor kayıt noktası bulunamadı."
        )

    advanced = advanced.replace(
        advanced_capture_marker,
        """              children: [
                FamilyRecordCapture.standings(
                  mode: title,
                  standings: standings,
                ),
                Text(
                  title,""",
        1,
    )

    advanced_share_marker = """                const SizedBox(height: 18),
                FilledButton.icon(
                  onPressed: () {
                    Navigator.of(context).pushReplacement(
                      MaterialPageRoute(
                        builder: replayBuilder,"""

    if advanced_share_marker not in advanced:
        raise RuntimeError(
            "Gelişmiş mod paylaşım düğmesi ekleme noktası bulunamadı."
        )

    advanced = advanced.replace(
        advanced_share_marker,
        """                const SizedBox(height: 15),
                SocialShareButton(
                  dark: true,
                  title: title,
                  text: SocialShareService.standingsText(
                    title: title,
                    headline: headline,
                    standings: standings,
                  ),
                ),
                const SizedBox(height: 10),
                FilledButton.icon(
                  onPressed: () {
                    Navigator.of(context).pushReplacement(
                      MaterialPageRoute(
                        builder: replayBuilder,""",
        1,
    )

    main, version_count = re.subn(
        r"Bilgi Rotası • Sürüm 1\.27(?:\.\d+)?",
        "Bilgi Rotası • Sürüm 1.28",
        main,
        count=1,
    )

    if version_count != 1:
        raise RuntimeError(
            "Ana menü sürüm yazısı güncellenemedi."
        )

    if "  share_plus:" not in pubspec:
        dependency_marker = "  audioplayers: ^6.8.1\n"

        if dependency_marker not in pubspec:
            raise RuntimeError(
                "share_plus bağımlılığı ekleme noktası bulunamadı."
            )

        pubspec = pubspec.replace(
            dependency_marker,
            dependency_marker
            + "  share_plus: 10.1.2\n",
            1,
        )

    pubspec = re.sub(
        r"^version:\s*.*$",
        f"version: {new_version}",
        pubspec,
        count=1,
        flags=re.MULTILINE,
    )

    MAIN.write_text(main, encoding="utf-8")
    QUICK.write_text(quick, encoding="utf-8")
    ADVANCED.write_text(advanced, encoding="utf-8")
    PUBSPEC.write_text(pubspec, encoding="utf-8")

    checks = {
        MAIN: [
            "import 'package:share_plus/share_plus.dart';",
            "part 'social_features.dart';",
            "SocialHomeButton(",
            "SocialShareService.careerText",
            "FamilyRecordCapture.board",
            "Bilgi Rotası • Sürüm 1.28",
        ],
        QUICK: [
            "FamilyRecordCapture.single",
            "SocialShareService.resultText",
        ],
        ADVANCED: [
            "FamilyRecordCapture.standings",
            "SocialShareService.standingsText",
        ],
        TARGET: [
            "class SocialShareService",
            "class FamilyRecordService",
            "class SocialHubScreen",
            "class FamilyRecordsScreen",
            "class ChallengeConfig",
            "class ChallengeLobbyScreen",
            "class ChallengeGameScreen",
            "class ChallengeResultScreen",
            "BR1-",
        ],
        PUBSPEC: [
            f"version: {new_version}",
            "share_plus: 10.1.2",
        ],
    }

    for path, markers in checks.items():
        text = path.read_text(encoding="utf-8")

        for marker in markers:
            if marker not in text:
                raise RuntimeError(
                    f"Kurulum doğrulaması başarısız: "
                    f"{path} / {marker}"
                )

    if shutil.which("flutter"):
        run(["flutter", "pub", "get"])
    else:
        print(
            "ℹ️ Flutter bu ortamda bulunamadı; "
            "pubspec.lock olmadan devam ediliyor."
        )

    if shutil.which("dart"):
        run([
            "dart",
            "format",
            "lib/main.dart",
            "lib/quick_modes.dart",
            "lib/advanced_modes.dart",
            "lib/social_features.dart",
        ])

    run(["git", "diff", "--check"])

    if shutil.which("flutter"):
        run([
            "flutter",
            "analyze",
            "--no-fatal-infos",
        ])

    files_to_stage = [
        "lib/main.dart",
        "lib/quick_modes.dart",
        "lib/advanced_modes.dart",
        "lib/social_features.dart",
        "pubspec.yaml",
    ]

    if Path("pubspec.lock").exists():
        files_to_stage.append("pubspec.lock")

    run([
        "git",
        "add",
        *files_to_stage,
    ])

    changed = subprocess.run(
        ["git", "diff", "--cached", "--quiet"],
        check=False,
    ).returncode != 0

    if not changed:
        raise RuntimeError(
            "Commit edilecek değişiklik bulunamadı."
        )

    run([
        "git",
        "commit",
        "-m",
        "Sosyal paylasim aile rekorlari ve meydan okuma kodu",
    ])
    committed = True

    run(["git", "push", "origin", "main"])

except Exception as error:
    if not committed:
        shutil.copy2(
            backup_dir / "main.dart",
            MAIN,
        )
        shutil.copy2(
            backup_dir / "quick_modes.dart",
            QUICK,
        )
        shutil.copy2(
            backup_dir / "advanced_modes.dart",
            ADVANCED,
        )
        shutil.copy2(
            backup_dir / "pubspec.yaml",
            PUBSPEC,
        )

        if TARGET.exists():
            TARGET.unlink()

        reset_paths = [
            "lib/main.dart",
            "lib/quick_modes.dart",
            "lib/advanced_modes.dart",
            "lib/social_features.dart",
            "pubspec.yaml",
        ]

        if Path("pubspec.lock").exists():
            reset_paths.append("pubspec.lock")

        subprocess.run(
            [
                "git",
                "reset",
                "--",
                *reset_paths,
            ],
            check=False,
        )

        if shutil.which("flutter"):
            subprocess.run(
                ["flutter", "pub", "get"],
                check=False,
            )

    print("")
    print("❌ Kurulum tamamlanamadı.")
    print(str(error))

    if committed:
        print(
            "Commit oluşturuldu fakat push başarısız oldu. "
            "Tekrar dene: git push origin main"
        )
    else:
        print(
            "Dosyalar önceki hâline otomatik döndürüldü."
        )

    raise SystemExit(1)

finally:
    shutil.rmtree(backup_dir, ignore_errors=True)

print("")
print("✅ Android paylaşım menüsü ve sonuç paylaşma düğmeleri eklendi.")
print("✅ Kariyer özeti paylaşımı eklendi.")
print("✅ Aynı telefondaki oyuncular için Aile Rekorları eklendi.")
print("✅ Soru kimliklerini taşıyan çevrim dışı BR1 meydan okuma kodu eklendi.")
print("✅ 10, 15 ve 20 soruluk hedef skorlu mücadele eklendi.")
print("✅ İki telefonda aynı soruların açılması sağlandı.")
print("✅ Ana ekrana Sosyal & Meydan Okuma düğmesi eklendi.")
print("✅ questions.json dosyasına dokunulmadı.")
print(f"✅ Yeni sürüm: {new_version}")
print("✅ Değişiklikler GitHub main dalına gönderildi.")
